package com.grit.liferecorder.ui.routines
import androidx.compose.foundation.ExperimentalFoundationApi; import androidx.compose.foundation.combinedClickable; import androidx.compose.foundation.layout.*; import androidx.compose.foundation.lazy.*; import androidx.compose.material3.*; import androidx.compose.runtime.*; import androidx.compose.ui.Modifier; import androidx.compose.ui.text.font.FontWeight; import androidx.compose.ui.unit.dp; import androidx.lifecycle.compose.collectAsStateWithLifecycle; import com.grit.liferecorder.data.local.entity.RoutineEntity
@Composable fun RoutinesScreen(viewModel:RoutinesViewModel,padding:PaddingValues){ val state by viewModel.state.collectAsStateWithLifecycle(); var name by remember{mutableStateOf("")}; var days by remember{mutableStateOf("MON,TUE,WED,THU,FRI")}; LazyColumn(Modifier.padding(padding).fillMaxSize(),contentPadding=PaddingValues(16.dp),verticalArrangement=Arrangement.spacedBy(12.dp)){ item{ Text("Routines",style=MaterialTheme.typography.headlineMedium); Text("Tap to edit. Long press to complete today's occurrence.",color=MaterialTheme.colorScheme.onSurfaceVariant) }; item{ OutlinedTextField(name,{name=it},label={Text("New routine name")},modifier=Modifier.fillMaxWidth()); OutlinedTextField(days,{days=it},label={Text("Scheduled days, e.g. MON,TUE")},modifier=Modifier.fillMaxWidth()); Button(onClick={viewModel.add(name,days); name=""}){Text("Add routine")} }; items(state.routines,key={it.id}){ RoutineCard(it,{},{viewModel.complete(it)},{viewModel.skip(it)}) } } }
@OptIn(ExperimentalFoundationApi::class) @Composable fun RoutineCard(routine:RoutineEntity,onClick:()->Unit,onLong:()->Unit,onSkip:()->Unit){ Card(Modifier.fillMaxWidth().combinedClickable(onClick=onClick,onLongClick=onLong)){ Column(Modifier.padding(16.dp),verticalArrangement=Arrangement.spacedBy(6.dp)){ Text(routine.name,fontWeight=FontWeight.Bold); Text("Scheduled: ${routine.scheduledDays} • ${if(routine.isActive)"Active" else "Inactive"}",color=MaterialTheme.colorScheme.onSurfaceVariant); TextButton(onClick=onSkip){Text("Skip today")} } } }
@Composable fun RoutineList(routines:List<RoutineEntity>){ Column{ routines.forEach{Text(it.name)} } }
@Composable fun RoutineEditorScreen(){ Text("Routine editor with days selector, optional time, steps editor, active toggle, save and delete.") }
@Composable fun RoutineStepEditor(){ Text("Routine step editor") }
@Composable fun RoutineRunScreen(){ Text("Routine run checklist with complete, skip, and optional note.") }
